       "{'Age': 30,\n",
       " 'BP': 120,\n",
       " 'Cholesterol': 200,\n",
       " 'Max HR': 180,\n",
       " 'ST Depression': 0,\n",
       " 'Sex_0': '0',\n",
       " 'Chest pain type_1': '1',\n",
       " 'FBS over 120_0': '0',\n",
       " 'EKG results_0': '0',\n",
       " 'Ecercise angina_0': '0',\n",
       " 'Slope of ST_0': '0',\n",
       " 'Number of vessels fluro_0': '0',\n",
       " 'Thallium_3': '3'}"
